local LCityBase = require("LApp.gameplay.city.base.LCityBase")
---@class LCityBuildingDropHud:LCityBase
local LCityBuildingDropHud = classX("LCityBuildingDropHud", LCityBase)
local typeOfFollowTransform = typeof(ProjectX.CFollowTransform)
local _timer = {
    work = "work",
    showProduce = "showProduce"
}
function LCityBuildingDropHud:ctor()
    self._hudObj = nil
    self._dropTrans = nil
    self._buildingRefId = 0
    self._index = 0
    self._iconInfoObj = nil
    self._ProduceObj = nil
    self._iconSlider = nil
    self._icon = nil
    self._produceIcon = nil
    self._produceText = nil
    self._followTransformComponent = nil
    self._init = false
    self._inWork = false
    self._needWorkTime = 0
    self._curWorkTime = 0
    self._maxProduceNum = 0
    self._showTextTime = 1
    self._curShowTextTime = 0
    self._workTimer = nil
    self._showProduceTimer = nil
    self._iconSprite = nil
    self._produceSprite = nil
end

function LCityBuildingDropHud:Initialize()
    LCityBase.Initialize(self)
    self._showTextTime = 1
end
function LCityBuildingDropHud:Dispose()

    if(self._workTimer)then
        MgrCenter.TimerMgr:RemoveTimer(self._workTimer)
    end
    if(self._showProduceTimer)then
        MgrCenter.TimerMgr:RemoveTimer(self._showProduceTimer)
    end
    if(self._iconSprite)then
        self._iconSprite:Dispose()
    end
    if(self._produceSprite)then
        self._produceSprite:Dispose()
    end
    DestroyObject(self._hudObj.gameObject)
    LCityBase.Dispose(self)
end
function LCityBuildingDropHud:InitHud(hudObj,dropTrans,buildingRefId,index)
    local hud = InstantObject(hudObj)
    hud.name = buildingRefId.."-"..index
    hud.transform:SetParent(MgrCenter.UIMgr._hudCanvasTrans)
    hud.transform.localPosition = Vector3.zero
    hud.transform.localScale = Vector3.one
    self._hudObj = hud;
    self._dropTrans = dropTrans
    self._buildingRefId = buildingRefId
    self._index = index
    self:InitObject()
    self:RefreshBuildingInfo()
    self._init = true
end
function LCityBuildingDropHud:InitObject()
    self._followTransformComponent = self._hudObj.gameObject:GetComponent(typeOfFollowTransform)
    if(self._followTransformComponent == nil)then
        self._followTransformComponent = self._hudObj.gameObject:AddComponent(typeOfFollowTransform)
    end
    local followTarget = FindChild(self._dropTrans.transform,"TopNode")
    self._followTransformComponent:SetTarget(followTarget)
    self._followTransformComponent:SetUIOffset(Vector2(0,0))
    self._iconInfoObj = FindChild(self._hudObj.transform,"IconInfo")
    self._ProduceObj = FindChild(self._hudObj.transform,"ProduceNum")
    self._iconSlider = LxUiHelper.FindImage(self._hudObj.transform,"IconInfo/IconSlider")
    self._icon = LxUiHelper.FindImage(self._hudObj.transform,"IconInfo/Icon")
    self._produceIcon = LxUiHelper.FindImage(self._hudObj.transform,"ProduceNum/Icon")
    self._produceText = LxUiHelper.FindText(self._hudObj.transform,"ProduceNum/Text")
end
function LCityBuildingDropHud:RefreshBuildingInfo()

    ShowObject(self._ProduceObj.gameObject,false)
    local hasTime,curTime,produceMaxNum = CtrlCenter.Building:GetBuildingWorkerTimeProduc(self._buildingRefId)

    if(hasTime > 0 and produceMaxNum > 0)then
        self._inWork = true
    else
        self._inWork = false
    end

    local peopleNum = CtrlCenter.Building:GetBuildingWorkerNum(self._buildingRefId)
    local peoples = CtrlCenter.Building:GetBuildingWorker(self._buildingRefId)
    local hasPeople = false
    for i, v in ipairs(peoples) do
        if(v > 0)then
            if(self._index == i)then
                hasPeople = true
            end
        end
    end
    self._maxProduceNum = string.format("%.2f",produceMaxNum / peopleNum)
    local state = CtrlCenter.City:GetCurTimeState()
    if(state == 2)then
        if(self._inWork and self._inView and hasPeople)then
            ShowObject(self._hudObj.gameObject,true)
            local totalTime = GetTimestamp() + hasTime
            self._workTimer = MgrCenter.TimerMgr:StartTimer(_timer.work..self._buildingRefId..self._index,0.01,false,-1, function()

                local curTime1 = totalTime - GetTimestamp()
                if(curTime1 <= 0)then
                    totalTime = GetTimestamp() + hasTime
                    if(self._ProduceObj == nil)then
                       return
                    end
                    ShowObject(self._ProduceObj.gameObject,true)
                    if(self._showProduceTimer)then
                        MgrCenter.TimerMgr:RemoveTimer(self._showProduceTimer)
                    end
                    self._showProduceTimer = MgrCenter.TimerMgr:StartTimer(_timer.showProduce..self._buildingRefId..self._index,0.5,false,1, function()
                        if(self._ProduceObj == nil)then
                            return
                        end
                        ShowObject(self._ProduceObj.gameObject,false)
                    end)
                end
                if(self._iconSlider == nil)then
                    return
                end
                self._iconSlider.fillAmount = (hasTime - curTime1)/hasTime

            end)
        else
            ShowObject(self._hudObj.gameObject,false)
            return
        end
    else
        ShowObject(self._hudObj.gameObject,false)
        return
    end
    local buildRef = GameTable.BuildingRef[self._buildingRefId]
    if(self._iconSprite == nil)then
        self._iconSprite = require("LApp.component.res.LxSprite"):new(self._icon)
    end
    if(self._produceSprite == nil)then
        self._produceSprite = require("LApp.component.res.LxSprite"):new(self._produceIcon)
    end
    self._iconSprite:SetSprite(buildRef.icon1)
    self._produceSprite:SetSprite(buildRef.icon1)
    --self:SetImage(self._icon,buildRef.icon1)
    --self:SetImage(self._produceIcon,buildRef.icon1)
    self:SetText(self._produceText,self._maxProduceNum)

end
function LCityBuildingDropHud:PlayInView()
    self._inView = true
    self:RefreshBuildingInfo();

end
function LCityBuildingDropHud:PlayOutView()
    self._inView = false
    self:RefreshBuildingInfo()
end
